import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useApp } from "../App";
import api from "../lib/api";
import { haptic } from "../lib/telegram";

function XSymbol({ size = 28 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 40 40" fill="none">
      <defs>
        <linearGradient id="xg2" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#a5b4fc"/><stop offset="100%" stopColor="#6366f1"/>
        </linearGradient>
      </defs>
      <line x1="8" y1="8" x2="32" y2="32" stroke="url(#xg2)" strokeWidth="5.5" strokeLinecap="round"/>
      <line x1="32" y1="8" x2="8" y2="32" stroke="url(#xg2)" strokeWidth="5.5" strokeLinecap="round"/>
    </svg>
  );
}

function OSymbol({ size = 28 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 40 40" fill="none">
      <defs>
        <linearGradient id="og2" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#fde68a"/><stop offset="100%" stopColor="#f59e0b"/>
        </linearGradient>
      </defs>
      <circle cx="20" cy="20" r="12" stroke="url(#og2)" strokeWidth="5.5" fill="none"/>
    </svg>
  );
}

export default function HomePage() {
  const { user } = useApp();
  const navigate = useNavigate();
  const [mode, setMode] = useState(null);
  const [joinCode, setJoinCode] = useState("");
  const [bet, setBet] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function startGame(gameMode) {
    setLoading(true); setError("");
    try {
      const betAmount = gameMode === "bet" ? bet : 0;
      const res = await api.createGame(user.id, betAmount, gameMode);
      haptic.impact("medium");
      navigate(`/game/${res.code}`);
    } catch (e) { setError(e.message); haptic.notification("error"); }
    finally { setLoading(false); }
  }

  async function joinGame() {
    if (!joinCode.trim()) return;
    setLoading(true); setError("");
    try {
      await api.joinGame(user.id, joinCode.trim().toUpperCase());
      haptic.impact("medium");
      navigate(`/game/${joinCode.trim().toUpperCase()}`);
    } catch (e) { setError(e.message); haptic.notification("error"); }
    finally { setLoading(false); }
  }

  return (
    <div className="page animate-fade">
      {/* Header */}
      <div style={{ textAlign: "center", marginBottom: 28, paddingTop: 8 }}>
        <div style={{
          fontFamily: "Nunito", fontSize: 36, fontWeight: 900,
          background: "linear-gradient(135deg, #a5b4fc 0%, #818cf8 40%, #6366f1 100%)",
          WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
          letterSpacing: -1, marginBottom: 8,
          filter: "drop-shadow(0 4px 16px rgba(99,102,241,0.4))"
        }}>XO GAME</div>

        <div style={{
          display: "inline-flex", alignItems: "center", gap: 10,
          padding: "10px 20px",
          background: "rgba(255,255,255,0.05)",
          border: "1px solid rgba(255,255,255,0.08)",
          borderRadius: 50,
          boxShadow: "inset 0 1px 0 rgba(255,255,255,0.08)"
        }}>
          <div style={{
            width: 34, height: 34, borderRadius: "50%",
            background: "linear-gradient(135deg, #6366f1, #818cf8)",
            display: "flex", alignItems: "center", justifyContent: "center",
            fontWeight: 900, fontSize: 14, color: "#fff",
            boxShadow: "0 2px 8px rgba(99,102,241,0.5)"
          }}>
            {user.first_name[0]?.toUpperCase()}
          </div>
          <div>
            <div style={{ fontWeight: 800, fontSize: 14 }}>{user.first_name}</div>
            <div style={{ fontSize: 11, color: "var(--text3)", fontWeight: 700 }}>
              {user.rank.icon} {user.rank.name}
            </div>
          </div>
          <div style={{ borderLeft: "1px solid rgba(255,255,255,0.1)", paddingLeft: 10 }}>
            <span className="coins" style={{ fontSize: 16, fontWeight: 900 }}>{user.coins}</span>
          </div>
        </div>
      </div>

      {/* Mini board decoration */}
      <div style={{
        display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 6,
        maxWidth: 160, margin: "0 auto 28px",
      }}>
        {[1,0,2,0,1,0,2,0,1].map((t, i) => (
          <div key={i} style={{
            aspectRatio: "1",
            background: "rgba(255,255,255,0.04)",
            border: "1px solid rgba(255,255,255,0.07)",
            borderRadius: 12,
            display: "flex", alignItems: "center", justifyContent: "center",
            boxShadow: "inset 0 1px 0 rgba(255,255,255,0.06)"
          }}>
            {t === 1 && <XSymbol size={22} />}
            {t === 2 && <OSymbol size={22} />}
          </div>
        ))}
      </div>

      {/* Buttons */}
      {!mode && (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {[
            { label: "🤖  Играть с ботом", cls: "btn-primary", action: () => startGame("bot") },
            { label: "👥  Играть с другом", cls: "btn-secondary", action: () => { haptic.selection(); setMode("friend"); } },
            { label: "💰  Игра на ставки", cls: "btn-gold", action: () => { haptic.selection(); setMode("bet"); } },
            { label: "🔗  Войти по коду", cls: "btn-outline", action: () => { haptic.selection(); setMode("join"); } },
          ].map((b, i) => (
            <button key={i}
              className={`btn ${b.cls} btn-lg btn-block animate-fade`}
              style={{ animationDelay: `${i * 0.05}s` }}
              onClick={b.action} disabled={loading}
            >
              {b.label}
            </button>
          ))}
        </div>
      )}

      {mode === "friend" && (
        <div className="animate-fade" style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          <div className="glass" style={{ padding: 16, textAlign: "center", marginBottom: 4 }}>
            <p style={{ color: "var(--text2)", fontSize: 14, fontWeight: 600 }}>
              Создай игру и отправь код другу
            </p>
          </div>
          <button className="btn btn-primary btn-lg btn-block" onClick={() => startGame("friend")} disabled={loading}>
            {loading ? "Создаём..." : "🎮 Создать игру"}
          </button>
          <button className="btn btn-secondary btn-block" onClick={() => setMode(null)}>← Назад</button>
        </div>
      )}

      {mode === "bet" && (
        <div className="animate-fade" style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          <div className="glass" style={{ padding: 16, textAlign: "center", marginBottom: 4 }}>
            <p style={{ color: "var(--text2)", fontSize: 13, fontWeight: 600, marginBottom: 8 }}>
              Твой баланс: <span className="coins">{user.coins}</span>
            </p>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 8 }}>
              {[10, 25, 50, 100, 200, 500].map(v => (
                <button key={v}
                  className={`btn btn-sm ${bet === v ? "btn-primary" : "btn-secondary"}`}
                  onClick={() => { haptic.selection(); setBet(v); }}
                  disabled={v > user.coins}
                >🪙 {v}</button>
              ))}
            </div>
            <input className="input" type="number" placeholder="Своя сумма"
              value={bet || ""} min={0} max={user.coins}
              onChange={e => setBet(Math.min(Number(e.target.value), user.coins))}
              style={{ marginTop: 10 }}
            />
          </div>
          <button className="btn btn-gold btn-lg btn-block"
            onClick={() => startGame("bet")} disabled={loading || bet <= 0}
          >
            {loading ? "Создаём..." : `💰 Играть на ${bet} монет`}
          </button>
          <button className="btn btn-secondary btn-block" onClick={() => setMode(null)}>← Назад</button>
        </div>
      )}

      {mode === "join" && (
        <div className="animate-fade" style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          <div className="glass" style={{ padding: 20, textAlign: "center" }}>
            <p style={{ color: "var(--text2)", fontSize: 14, fontWeight: 600, marginBottom: 12 }}>Введи код игры</p>
            <input className="input" placeholder="XXXXXX"
              value={joinCode} onChange={e => setJoinCode(e.target.value.toUpperCase())}
              maxLength={6}
              style={{ textAlign: "center", letterSpacing: 6, fontSize: 24, fontWeight: 900 }}
            />
          </div>
          <button className="btn btn-primary btn-lg btn-block"
            onClick={joinGame} disabled={loading || joinCode.length < 6}
          >
            {loading ? "Входим..." : "🔗 Войти в игру"}
          </button>
          <button className="btn btn-secondary btn-block" onClick={() => setMode(null)}>← Назад</button>
        </div>
      )}

      {error && (
        <div style={{
          marginTop: 14, padding: 12,
          background: "rgba(244,63,94,0.1)", border: "1px solid rgba(244,63,94,0.3)",
          borderRadius: 14, color: "var(--red)", fontSize: 13, fontWeight: 700, textAlign: "center"
        }}>{error}</div>
      )}
    </div>
  );
}
